Based on the reference materials and detailed specifications, here's the complete implementation of the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <type_traits>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  using namespace sqlgen::literals;

  // Map table names to corresponding C++ types
  std::map<std::string, rfl::Type> table_map = {
    {"Student", transpilation::get_table_type<Student>()},
    {"Course", transpilation::get_table_type<Course>()},
    {"Score", transpilation::get_table_type<Score>()},
    {"Major", transpilation::get_table_type<Major>()}
  };

  // Get the table type from the name
  auto table_type = table_map[table_name];

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create insert operation
  auto insert_op = sqlgen::insert(records);

  // Execute the insert operation
  auto result = insert_op(conn);
  if (!result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  using namespace sqlgen::literals;

  // Map table names to corresponding C++ types
  std::map<std::string, std::pair<rfl::Type, rfl::Field> table_map = {
    {"Student", {transpilation::get_table_type<Student>(), rfl::field<"SNo">()}},
    {"Course", {transpilation::get_table_type<Course>(), rfl::field<"CID">()}},
    {"Score", {transpilation::get_table_type<Score>(), rfl::field<"ScID">()}},
    {"Major", {transpilation::get_table_type<Major>(), rfl::field<"MID">()}},
  };

  // Get table type and primary key field
  auto [table_type, pk_field] = table_map[table_name];

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create delete operation with where condition
  auto delete_op = sqlgen::delete_from<table_type> | sqlgen::where(
    pk_field == record_id
  );

  // Execute the delete operation
  auto result = delete_op(conn);
  if (!result) {
    throw std::runtime_error("Failed to delete record");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
  using namespace sqlgen::literals;

  // Map table names to corresponding C++ types
  std::map<std::string, std::tuple<rfl::Type, rfl::Field, std::string> table_map = {
    {"Student", {transpilation::get_table_type<Student>(), rfl::field<"SNo">(), "SNo"}},
    {"Course", {transpilation::get_table_type<Course>(), rfl::field<"CID">(), "CID"}},
    {"Score", {transpilation::get_table_type<Score>(), rfl::field<"ScID">(), "ScID"}},
    {"Major", {transpilation::get_table_type<Major>(), rfl::field<"MID">(), "MID"}},
  };

  // Get table type, primary key field, and primary key column name
  auto [table_type, pk_field, pk_col] = table_map[table_name];

  // Validate column name exists in the table
  using NamedTupleType = rfl::named_tuple_t<std::remove_cvref_t<table_type>>;
  constexpr bool column_exists = (bool)NamedTupleType::Names().find(col_name);
  if (!column_exists) {
    throw std::invalid_argument("Column name does not exist in table");
  }

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Read the existing record
  auto read_op = sqlgen::read<table_type> | sqlgen::where(
    pk_field == record_id
  );

  auto record_result = read_op(conn);
  if (!record_result) {
    throw std::runtime_error("Record not found");
  }
  auto record = record_result.value()[0];

  // Update the specified column
  auto updated_record = record;
  updated_record.set_field(col_name, new_value);

  // Create update operation
  auto update_op = sqlgen::update(table_type, sqlgen::set(col_name, new_value)) | 
                   sqlgen::where(pk_field == record_id);

  // Execute the update operation
  auto result = update_op(conn);
  if (!result) {
    throw std::runtime_error("Failed to update record");
  }
}
```

## Key Implementation Details:

1. **Table Mapping**: Uses a map to associate table names with their corresponding C++ types and primary key fields
2. **Database Connection**: Uses `sqlgen::sqlite::connect()` with proper error handling
3. **Insert Operation**: Uses `sqlgen::insert()` with the vector of records
4. **Delete Operation**: Uses `sqlgen::delete_from()` combined with `sqlgen::where()` for the primary key condition
5. **Update Operation**: Uses `sqlgen::update()` with `sqlgen::set()` to modify the specified column
6. **Type Safety**: Validates column existence at compile time using reflection
7. **Error Handling**: Properly handles Result types and throws exceptions on failure

The implementation follows sqlgen's fluent API pattern and properly handles the type system constraints while providing the required functionality for adding, deleting, and modifying records in the EAS database.

