#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

  // Chain operations using functional style
  auto result = conn_result
    .and_then([](auto conn) { return conn->begin_transaction(); })
    .and_then([](auto conn) {
      // Delete users with last_login before 2025-01-01
      return (sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01"))(*conn);
    })
    .and_then([](auto conn) { return conn->commit(); });

  // Return 0 for success, 1 for failure
  return result ? 0 : 1;
}

} // namespace delete_inactive_users
```

