    // Execute the CREATE VIEW statement
    std::string sql = sqlgen::transpilation::to_sql(create_view_stmt);
    auto exec_result = conn->execute(sql);

    return exec_result ? true : false;

  } catch (const std::exception& e) {
    // Handle any exceptions during execution
    return false;
  }
}

