```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <algorithm>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user_id1;
  int user_id2;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
  // Composite primary key handled by sqlgen
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // 1. Create in-memory SQLite database connection
  auto conn_result = sqlgen::sqlite::connect(":memory:");
  if (!conn_result) {
    return {};
  }
  auto conn = conn_result.value();

  // 2. Create table schemas
  auto create_user_table = sqlgen::create_table<User>;
  auto create_friendship_table = sqlgen::create_table<Friendship>;

  // 3. Insert sample data
  auto insert_users = sqlgen::insert(users);
  auto insert_friendships = sqlgen::insert(friendships);

  // Execute table creation
  create_user_table(conn).value();
  create_friendship_table(conn).value();

  // Insert data
  insert_users(conn).value();
  insert_friendships(conn).value();

  // 4. Execute required SQL queries using sqlgen's query building capabilities

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends_query = 
      select_from<User, "u1">("username"_t1 | as<"user1_name">, "username"_t2 | as<"user2_name">)
      | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
      | inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
      | inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
      | where("user_id"_t1 < "user_id"_t2)
      | group_by("user_id"_t1, "user_id"_t2)
      | having(count() > 0);

  // Query 2: Users with more than average friends using nested query
  auto avg_friends_subquery = 
      select_from<User, "u">(count_distinct("user_id2"_t1) | as<"friend_count">)
      | group_by("user_id"_t1);

  auto above_avg_friends_query = 
      select_from<User, "u">("username"_t1)
      | left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t1)
      | group_by("user_id"_t1)
      | having(count_distinct("user_id2"_t1) > 
          (select_from<avg_friends_subquery>() | to<double>).value());

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend_query = 
      select_from<User, "u1">("username"_t1 | as<"user1_name">, "username"_t2 | as<"user2_name">)
      | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
      | inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
      | inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
      | where("user_id"_t1 != "user_id"_t2 && count_distinct("user_id2"_t1) == 1);

  // Query 4: Count friends per user
  auto friends_count_query = 
      select_from<User, "u">("username"_t1, count_distinct("user_id2"_t1) | as<"friend_count">)
      | left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t1);

  // Query 5: Recommendation - users in same city not yet friends
  auto recommendation_query = 
      select_from<User, "u1">("username"_t1 | as<"user1_name">, "username"_t2 | as<"user2_name">)
      | inner_join<User, "u2">("city"_t1 == "city"_t2 && "user_id"_t1 < "user_id"_t2)
      | where(!exists(select_from<Friendship, "f">("user_id1"_t1 == "user_id"_t1 && "user_id2"_t1 == "user_id"_t2)));

  // 5. Process results and return appropriate data structure
  // For this implementation, we'll focus on mutual friends and friend recommendations
  auto mutual_results = mutual_friends_query(conn).value();
  auto recommendation_results = recommendation_query(conn).value();

  std::vector<FriendConnection> results;
  results.reserve(mutual_results.size() + recommendation_results.size());

  // Process mutual friends
  for (const auto& row : mutual_results) {
    results.emplace_back(
        std::get<"user1_name">(row),
        std::get<"user2_name">(row)
    );
  }

  // Process recommendations
  for (const auto& row : recommendation_results) {
    results.emplace_back(
        std::get<"user1_name">(row),
        std::get<"user2_name">(row)
    );
  }

  return results;
}

}  // namespace analyze_social_network
